package base;import com.microsoft.playwright.*;import org.junit.jupiter.api.*;public class BaseTestPlaywright {    protected static Playwright playwright;    protected static Browser browser;    protected BrowserContext context;    protected Page page;    @BeforeAll    static void iniciarPlaywright() {        playwright = Playwright.create();        browser = playwright.chromium().launch(                new BrowserType.LaunchOptions()                        .setHeadless( System.getenv("GITHUB_ACTIONS") != null)        );    }    @BeforeEach    void abrirNavegador() {        context = browser.newContext(                new Browser.NewContextOptions()                        .setViewportSize(1366, 768)        );        page = context.newPage();    }    @AfterEach    void cerrarContexto() {        if (context != null) {            context.close();        }    }    @AfterAll    static void cerrarPlaywright() {        if (browser != null) {            browser.close();        }        if (playwright != null) {            playwright.close();        }    }}